var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크아악-! 아파, 아프다고, 메이슨 씨!","JPN":"くああっ！　痛い、痛いって、メイソンさん！","ENG":"Aaaargh! It hurts, Mr. Mason!","TWN":"呃啊啊–！好、好痛，梅森！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"엄살 피우긴. 대령은 카일이나 실비아에 비하면 양호한 편이야.","JPN":"大袈裟な。大佐はカイルやシルビアに比べたらマシなほうなんだぞ。","ENG":"Quit whining. Compared to Kyle or Sylvia, you're getting off easy.","TWN":"少無病呻吟了，上校比起凱爾和希爾維亞還算好的了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"애당초 대령 몸은 워낙 튼튼해서 이정도로는 안 죽는다고.","JPN":"そもそも、大佐の体は丈夫すぎてこの程度じゃ死なねえよ。","ENG":"With that ironclad body of yours, this much won't kill you anyway.","TWN":"你的身體本來就很健壯，這點程度不會死的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"죽는 게 아니라 아프다고! 사람이 말을 하면 좀 들어!","JPN":"死ぬんじゃなくて痛いって！　人の話を聞け！","ENG":"I'm not dying, I'm hurting! Try listening when a guy says something!","TWN":"不是會死而是會痛！拜託你聽聽別人說什麼！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후후. 역시 군인은 나약하군. 이런 작은 싸움에서 저런 부상이라니 말이야.","JPN":"ふふ。やっぱり軍人は弱いな。この規模の戦いであれだけ負傷するなんて。","ENG":"Haha. Soldiers are too soft. Taking wounds like that from a minor scrap.","TWN":"呵呵，軍人果然很脆弱，居然在這種小戰鬥受那種傷。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"하하! 짬밥이나 먹는 녀석들이 힘을 쓰겠어?","JPN":"はは！　キャリア組は荒仕事しないからな！","ENG":"Haha! Chow-line grunts don't have real strength.","TWN":"哈哈！吃部隊伙食的傢伙能使得上力嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"아무렴. 몇 번이나 생사의 고비를 넘긴 우리 같은 용병들에겐 우스울 지경이지.","JPN":"ああ、何度も死線を超えてきた俺たち傭兵にとっては、こんな戦いなんてザラだよな。","ENG":"Right. For mercs like us who've cheated death a few times, this is laughable.","TWN":"想當然，對我們這種度過好幾次生死關頭的傭兵來說很可笑。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하하하!!","JPN":"ははは！！","ENG":"Hahaha!!","TWN":"哈哈哈！！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제길… 이건 부당해. 가장 힘든 임무를 맡은 내 취급이 왜 이런 식이냐고!","JPN":"くそ……理不尽だ。俺の任務が一番大変だったのに、扱いが雑すぎるんじゃないか！","ENG":"Damn it... this is unfair. Why am I getting treated like this when I was given the toughest job?!","TWN":"該死…這不公平，負責執行最艱難任務的我，為什麼會受到這種待遇！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그 말은 넘어가기 힘드네요. 작전팀 이외에도 다들 여러가지로 고생했다고요.","JPN":"その言葉は聞き捨てなりませんね。作戦チーム以外のみんなも色々と大変だったのに。","ENG":"Hard to let that slide. Folks outside the operations team busted their backs too.","TWN":"這話實在聽不下去，除了作戰組以外，大家也都吃了不少苦。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"침식체를 상대하는 게, 어쩌면 대피소 진상들을 상대하는 것보다 편하다는 걸 아셔야죠.","JPN":"侵食体と戦っている方が、避難所でクレーマーの相手をするよりは楽ってこともあるんですからね。","ENG":"Think fighting C.O.s is rough? Try babysitting a shelter full of whiners.","TWN":"你應該要知道，對付侵蝕體也許比對付避難所那些討厭的人還輕鬆。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 기운을 차려서 다행이군.","JPN":"皆元気そうでなによりだ。","ENG":"I'm glad to see everyone getting their strength back.","TWN":"幸好大家都打起精神來了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 다른 분들도 무사히 치료 중이라고 합니다.","JPN":"はい。他の方々も無事治療を受けているようです。","ENG":"Yes. The others are being treated safely as well.","TWN":"是，其他人也在順利接受治療中。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"다만… 대균열을 막는 건 실패했으니, 도시가 붕괴되는 건 시간문제겠죠.","JPN":"ただ……大亀裂は止められなかったので、都市の崩壊は時間の問題でしょう。","ENG":"But... since we failed to halt the Grand Dimension Crevice, the city's collapse is a matter of time.","TWN":"但是…因為阻擋大峽谷失敗，所以城市早晚會崩壞。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당장은 인명피해를 줄인데 만족하지. 살아만 있으면 어떻게든 그 다음이 있는 법이니까.","JPN":"今は人的被害を抑えられたことに満足しよう。生きてさえいれば、次のチャンスはやってくるものだからな。","ENG":"For now, be satisfied we cut casualties. If you're alive, there's always another way next time.","TWN":"暫時減少人員傷亡已經很滿足了，只要能活下來，無論如何都會有下一次機會。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다만, 이곳에 마련될 나나하라 가문연합의 봉인역도 언젠간 제 힘을 다할 거야.","JPN":"だが、ここに設けられる七原家連合の封印域もいつか限界が来る。","ENG":"Still, the Domain the Nanahara Family Alliance set here will run out of power someday.","TWN":"但是，要在這裡設置的七原家族聯盟封印域總有一天力量也會用盡。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"준비했던 선로전환기 역시 지키지 못했고, 대균열의 뿌리는 멈추지 않을 테니…….","JPN":"用意した線路転換器も守れなかったし、大亀裂の根は止まらない……","ENG":"We couldn't protect the Track Switcher, and the Grand Dimension Crevice's roots won't stop...","TWN":"之前準備的線路轉換器果然沒能守住，大峽谷的根部應該不會停止……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우릴 지킬 결계가 깨지면, 앞으로 마주해야 할 건 지금까지와는 다른 붉은 하늘이겠지.","JPN":"我々を守ってくれる結界が破れたら、今までとは違う赤い空を目にすることになるだろう。","ENG":"When the barrier breaks, what awaits will be a different crimson sky than before.","TWN":"要是守護我們的結界被打破，之後要面臨的應該是和目前為止不一樣的紅色天空吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"결국… 클리포트 게임이라는 악몽이 반복되겠군요.","JPN":"結局……クリフォトゲームという悪夢が繰り返されるんですね。","ENG":"In the end... the nightmare called the Qliphoth Game repeats.","TWN":"最後…逆卡巴拉遊戲這個惡夢應該會反覆出現。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 이러나저러나, 이후의 일은 최고 관리자에게 기댈 수밖에 없겠군.","JPN":"ああ。なんやかんや、後のことは最高管理者に頼るしかないな。","ENG":"Yes. One way or another, we'll have to rely on the Supreme Administrator now.","TWN":"是啊，不管怎樣，之後的事應該只能依靠最高管理者了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"부디, 그 자가 준비한 안배가…….","JPN":"どうか、彼の采配が……","ENG":"Let's hope the arrangements he prepared...","TWN":"只希望那個人的安排……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다시금 세상을 지키길 바랄 뿐이네.","JPN":"再び世界を守ってくれることを願うばかりだ。","ENG":"Will protect the world once more.","TWN":"能再次守住這個世界。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……과연. 챔버의 상황은 파악했네.","JPN":"……なるほど。チェンバーの状況は把握した。","ENG":"...I see. I've grasped Chamber's situation.","TWN":"……果然掌握了密室的情況。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송합니다. 큰 기대를 받았건만, 제 힘이 부족해 도시를 온전히 지켜내지 못했습니다.","JPN":"申し訳ありません。大きな期待を寄せていただいたにも関わらず、力及ばず都市を守りきれませんでした。","ENG":"My apologies. You expected much, but my power was lacking and I couldn't fully protect the city.","TWN":"抱歉，雖然大家對我寄予厚望，但我的力量不足，沒辦法完整守住城市。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아, 아닙니다. 주군! 이번 일은, 순전히 제가 미숙했기에…….","JPN":"ち、違います、我が主！　今回の件は、私が未熟だったゆえ……","ENG":"N-no, Master! This was entirely my own inexperience...","TWN":"別、別這麼說，主君！這次的事純粹是因為我不成熟……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"챔버는 여섯 지부 중에서도 특히나 변수가 많던 도시야.","JPN":"チェンバーは6つの支部の中でも特に不確定要素が多かった都市だ。","ENG":"Chamber's always been the most volatile of the six branches.","TWN":"密室在六個分部當中也是變數特別多的城市。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"봉인전대인 고르디우스를 보낸 선택이 지금에 와서 잘못되었다고 생각되지는 않네.","JPN":"封印戦隊ゴルディウスを送り出すという選択は間違ってなかったと、今も思っている。","ENG":"I don't think sending the Gordias Seal Division was the wrong call, even now.","TWN":"事到如今，我不認為派封印戰隊哥帝爾斯的選擇是錯的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비록 도시를 지키지는 못했지만… 차원을 격리하는 봉인역의 힘으로 유예를 벌었으니 말이야.","JPN":"都市を守りきれなかったとはいえ……次元を隔離する封印域の力で時間稼ぎができるしね。","ENG":"We couldn't save the city... but the Domain isolating the dimension bought us a stay.","TWN":"儘管無法守住城市…卻以隔離次元的封印域力量暫緩了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"주인어른. 말씀은 감사합니다만, 이곳에 마련될 봉인역은 오롯이 나오님의 힘으로 만들어질 예정입니다.","JPN":"社長。ありがたいお言葉ですが、こちらの封印域は、完全にナオ様の力で作られる予定です。","ENG":"Master, thank you. But the Domain here will rely solely on Miss Nao's power.","TWN":"主人，謝謝你這麼說，但將在這裡建立的封印域，只會以奈緒的力量打造。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래. 그 마저도 명부신의 영혼이 아닌 북방합의체의 그림자 핵을 통한 방법이지.","JPN":"ああ。それも冥府の神の魂ではなく、北方合意体のシャドウの核を利用した方法じゃ。","ENG":"Right. And not the Nether God's souls, but the Northern Union's Shadow Core.","TWN":"沒錯，就連這個也不是透過冥府神的靈魂，而是透過北方和議會暗影核心的方法。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"결계를 유지하는 영혼의 격이 낮은 이상, 이 방법으로는 오래 못 버틴다.","JPN":"結界を維持する魂の格が低い以上、この方法では長く持たん。","ENG":"With souls of such low grade maintaining it, the barrier won't last long.","TWN":"維持結界的靈魂級別較低，用這個方法沒辦法撐太久。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 지부의 상황이 파악되고 있으니 곧 상황을 타개할 방법을 찾을 수 있을 걸세.","JPN":"他の支部の状況も把握中だから、もうじき打開策が見つかるさ。","ENG":"We're getting the other branches' status. Soon we'll find a way to break this stalemate.","TWN":"我們正在掌握其他分部的情況，應該很快就能找到解決辦法。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무리한 부탁인 건 알지만… 그때까지 힘써줬으면 좋겠군.","JPN":"無理な頼みなのは承知しているが……それまで頑張ってくれ。","ENG":"I know it's a lot to ask, but... hold out until then.","TWN":"雖然我知道是無理的請求…但希望妳能幫忙到那個時候。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"에잉. 예나 지금이나 정도를 모르는 녀석이로군.","JPN":"ったく。昔も今も、程度ってものが分からぬやつじゃ。","ENG":"Ugh. As ever, you don't know moderation.","TWN":"唉唷，不管是以前還是現在都是個不知分寸的傢伙。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐, 좋다. 기왕 이렇게 된 거, 네놈이 암군을 때려잡을 때까지 버텨보도록 하지.","JPN":"まあよい。こうなったからには、お主が暗君を叩きのめすまでなんとか持ちこたえてみよう。","ENG":"Fine. Since it has come to this, I will hold the line until you put down the Ignorant Monarch.","TWN":"好吧，既然如此，我會試著撐到你這傢伙擊敗昏君為止。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"든든하군. 역시 봉인전대의 전대장다워.","JPN":"頼もしい。さすがは封印戦隊の戦隊長だ。","ENG":"That's reassuring, coming from the commander of Seal Division.","TWN":"真可靠，果然是封印戰隊隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 별개로 자네에게 한 가지 부탁이 있네만.","JPN":"あ、それとは別に1つ頼みがあるのだが。","ENG":"Ah. On a separate matter, I have one more favor to ask.","TWN":"啊，我要另外拜託妳一件事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"켁. 아직 부탁할 게 남아있다고?","JPN":"げっ、まだあるのか？","ENG":"Gah. There's more?","TWN":"呃，你還有事情要拜託嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 정확하게는 자네를 통해 이야기를 나누고 싶은 상대가 있네.","JPN":"ああ。正確には、君を介してとある人と話をしたい。","ENG":"Yes. More precisely, there is someone I want to speak to through you.","TWN":"沒錯，準確來說，是有個想透過妳交談的對象。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮다면…….","JPN":"できれば……","ENG":"If it's no trouble...","TWN":"可以的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"북방합의체의 회선을 연결해줄 수 있나?","JPN":"北方合意体の回線を繋いでくれるかね？","ENG":"Can you patch me through to the Northern Union's line?","TWN":"能幫忙連接北方和議會的線路嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯哼……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"의외네. 설마 당신이 날 찾을 줄은 몰랐어.","JPN":"意外だな。君が私に連絡してくるとは。","ENG":"That was unexpected. Didn't think you would call me.","TWN":"真意外，沒想到你會找我。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"상황이 상황이니, 감언이설로 나를 속여 정보를 캐낼 심산이려나?","JPN":"私を口車に乗せて情報を引き出すつもりかな？","ENG":"Given the mess, planning to butter me up and fish for intel?","TWN":"情況都這麼糟了，還想用花言巧語欺騙我，挖取情報嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설마, 최고관리자로서 챔버를 지켜준데 감사를 표할 뿐이네.","JPN":"まさか。最高管理者として、チェンバーを守ってくれたことに礼を言いたいだけだ。","ENG":"Hardly. As Supreme Administrator, I wanted to express my gratitude for protecting Chamber.","TWN":"怎麼會？身為最高管理者，我是想對妳守護密室這件事表達謝意。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런 상황이지만, 서로 하고 싶은 이야기가 많을 테고 말이야.","JPN":"こんな状況だが、お互い話したいことも多いだろうしな。","ENG":"Even now, I'm sure we both have plenty to say.","TWN":"雖然情況如此，但彼此想說的話應該很多。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"글쎄? 최고관리자 나리가 합의체의 총참모장에게 어떤 이야기를 하고 싶은 지 모르겠네.","JPN":"さあな。最高管理者が合意体の総参謀長に話したいことなど、私には見当もつかないが。","ENG":"Not sure what the Supreme Administrator wants with the Northern Union's Chief of the General Staff.","TWN":"這個嘛？真不知道最高管理者有什麼話想跟和議會總參謀長說。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"봉인역이 있는 이상, 더 이상 내가 개입할 만한 일은 없지 않을까?","JPN":"封印域がある限り、これ以上私の介入が必要なことはないんじゃないか？","ENG":"With the Domain up, there's nothing left for me to meddle in, is there?","TWN":"既然有封印域了，應該不會再有我要插手的事了吧？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미리 첨언하자면, 난 전조에 한해 자네를 막을 생각이 없네.","JPN":"先に言っておくが、私は前兆の件に限っては君を止めるつもりはない。","ENG":"For the record, I won't be stopping you regarding omens.","TWN":"我先補充一句，除了前兆之外，我不打算阻攔妳。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 행했던 일들을 옹호할 생각은 없지만, 적어도 내게 그걸 비난할 자격은 없거든.","JPN":"君が行ったことを擁護するつもりはないが、少なくとも私にそれを非難する資格はないからね。","ENG":"I won't endorse what you've done, but I've no right to condemn it either.","TWN":"雖然我不打算擁護妳做過的那些事，但至少我沒資格指責。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"알아. 당신은 그런 사람이잖아.","JPN":"そう。君はそういう人間だ。","ENG":"I know. That's who you are.","TWN":"我知道，你不就是那種人嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그럴 듯한 말로 상대를 안심시키면서, 정작 필요한 것만 챙기는 실속 있는 사람.","JPN":"それっぽい言葉で相手を安心させ、いいとこ取りする打算的な人間。","ENG":"Soothing me with fine words while pocketing only what you need. Practical to the core, I see.","TWN":"用煞有其事的話讓對方安心，卻只顧及自己所需的人。"},"stage":{"bg":"MS_1302","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"내게 부탁할 게 있다면 편하게 말해도 돼. 적어도 지금은 당신과 입장이 같으니까.","JPN":"私に頼みがあるなら気兼ねなく言っていい。少なくとも今は君と同じ立場だからな。","ENG":"If you need a favor, say it. For now, we're on the same side.","TWN":"如果有事要拜託我可以儘管說，至少我們現在的立場相同。"},"stage":{"bg":"MS_1302","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음…… 그럼, 한 가지 궁금한 게 있네만.","JPN":"うむ……では、1つ聞きたいことがある。","ENG":"Mm... In that case, there is one thing I'm curious about.","TWN":"嗯……那麼我有一件好奇的事。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"응. 뭔데?","JPN":"ああ。何だ？","ENG":"Go on. What is it?","TWN":"嗯，什麼事？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나탈리아는 잘 지내나?","JPN":"ナタリアは元気かね？","ENG":"How is Natalia doing?","TWN":"那塔利亞過得好嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"뭐?","JPN":"何？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반응을 보니 잘 지내는 모양이군. 아무래도 괜한 걱정이었던 모양이야.","JPN":"その反応だと、元気なのだな。余計な心配だったようだ。","ENG":"From your reaction I see that she's fine. Seems I worried for nothing.","TWN":"看妳的反應她應該過得很好，總覺得是我白擔心了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 몸도 성치 않은데 편히 쉬게나.","JPN":"では、疲れているだろうし、ゆっくり休みたまえ。","ENG":"Then rest up. You don't sound to be in top shape.","TWN":"那麼，我看妳身體狀況也不好，就好好休息吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"뿌리가 가능성을 탐닉한다는 건, 암군이 세계의 규칙을 거슬러서라도 얻어내고 싶은 게 있다는 거야.","JPN":"根が可能性を貪るということは、暗君は世界のルールに逆らってでも手に入れたいものがあるということだ。","ENG":"If the roots feast on possibility, it means the Ignorant Monarch wants something enough to defy the world's rules.","TWN":"根部沉溺於可能性，這代表昏君就算違抗世界的規矩，也想獲得一些東西。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"반대로 말하면 뿌리가 향하는 곳이 당신이 다다라야 할 장소겠지.","JPN":"逆に言えば、根が向かう先こそが君のたどり着くべき場所だろう。","ENG":"Conversely, where the roots reach is where you need to go.","TWN":"反過來說，根部所向之處應該就是你要到達的地方。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"알고 있네.","JPN":"分かっている。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다만, 아직은 타기리온에 관한 정보가 부족해.","JPN":"だが、まだタギリオンの情報が足りない。","ENG":"But we still lack intel on Thagirion.","TWN":"但是目前關於塔基里翁的情報還不夠。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"괜찮아. 적어도 나아가고 있는 방향은 틀리지 않았으니까.","JPN":"大丈夫だ。進む方向は間違ってない。","ENG":"It's fine. At least you're heading the right way.","TWN":"沒關係，至少前進的方向沒錯。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그러니… 한번 열심히 발버둥 쳐봐, 관리자 나리.","JPN":"だから……頑張って足掻いてみるといい。最高管理者。","ENG":"So... struggle with all you've got, Administrator.","TWN":"所以…管理者，就試著努力掙扎一次吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"내 목적을 위해서라도, 당신은 암군에게 패배해선 안 되거든.","JPN":"私の目的のためにも……君が暗君に敗れては困る。","ENG":"For my goals too, you can't afford to lose to the Ignorant Monarch.","TWN":"就算是為了我的目標，你也不能敗給昏君。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 어느 쪽의 응원이라 생각하면 되겠나?","JPN":"それは、どちらからの応援と捉えるべきかね？","ENG":"Which side were those words of encouragement from?","TWN":"那可以想成是對哪一方的支持呢？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"일단은…….","JPN":"とりあえずは……","ENG":"For now...","TWN":"目前……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"양쪽 전부이려나?","JPN":"両方かな。","ENG":"Both, I'd say.","TWN":"是雙方？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거, 부담감이 두 배로군.","JPN":"なるほど、プレッシャーも2倍ってことか。","ENG":"Twice the pressure, then.","TWN":"這讓人壓力加倍啊。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도…….","JPN":"どうやら……","ENG":"In any case...","TWN":"不管怎麼說……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"질 수 없는 싸움이 되겠어.","JPN":"負けられない戦いになりそうだ。","ENG":"This just became a fight we cannot lose.","TWN":"會是場無法落敗的戰鬥。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};